namespace sv_df10c1747d5642cf8cfc2b630c665fb0.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

namespace sv_df10c1747d5642cf8cfc2b630c665fb0.Services;

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

namespace sv_df10c1747d5642cf8cfc2b630c665fb0.Services;

public class MockChatService : IChatService
{
    private readonly List<Channel> _channels;
    private readonly List<Message> _messages;
    private int _nextMessageId;

    public MockChatService()
    {
        _channels = new List<Channel>
        {
            new(1, "general", "General discussion and announcements", 3),
            new(2, "engineering", "Engineering team chat", 0),
            new(3, "design", "Design team discussions", 5),
            new(4, "random", "Water cooler chat", 1),
        };

        _messages = new List<Message>();
        _nextMessageId = 1;
        SeedMessages();
    }

    private void SeedMessages()
    {
        var now = DateTime.UtcNow;

        // #general
        AddMsg(1, "Alice", "Welcome to the team! 🎉", now.AddHours(-5),
            null, [new("👍", ["Bob", "Charlie"]), new("🎉", ["Diana"])]);
        AddMsg(1, "Bob", "Thanks Alice! Excited to be here.", now.AddHours(-4.5));
        var t1 = AddMsg(1, "Charlie", "Has anyone reviewed the new design specs?", now.AddHours(-3));
        AddMsg(1, "Diana", "Yes, I left some comments on the PR.", now.AddHours(-2.8), t1.Id);
        AddMsg(1, "Eve", "I'll take a look this afternoon.", now.AddHours(-2.5), t1.Id);
        AddMsg(1, "Alice", "Let's discuss in the standup tomorrow.", now.AddHours(-2));
        AddMsg(1, "Bob", "Sounds good! I have updates on the API refactor too.", now.AddHours(-1.5),
            null, [new("👀", ["Alice"])]);
        AddMsg(1, "Charlie", "Don't forget to update your timesheets by EOD.", now.AddMinutes(-45));
        var t2 = AddMsg(1, "Diana", "Anyone having issues with the build pipeline?", now.AddMinutes(-30));
        AddMsg(1, "Bob", "Yeah, the tests are flaky again.", now.AddMinutes(-25), t2.Id);
        AddMsg(1, "Alice", "I pushed a fix, try rebasing.", now.AddMinutes(-20), t2.Id);
        AddMsg(1, "Eve", "Confirmed, it's working now.", now.AddMinutes(-15), t2.Id);
        AddMsg(1, "Eve", "Great teamwork today everyone! 🚀", now.AddMinutes(-5),
            null, [new("❤️", ["Alice", "Bob", "Charlie"]), new("🚀", ["Diana"])]);

        // #engineering
        AddMsg(2, "Bob", "PR #142 is ready for review.", now.AddHours(-6));
        AddMsg(2, "Charlie", "I'll review it after lunch.", now.AddHours(-5));
        AddMsg(2, "Alice", "We need to update the CI config for the new test suite.", now.AddHours(-3),
            null, [new("👍", ["Bob"])]);
        AddMsg(2, "Diana", "Deployed v2.3.1 to staging.", now.AddHours(-1),
            null, [new("🎉", ["Alice", "Bob", "Charlie"])]);

        // #design
        AddMsg(3, "Diana", "New mockups are in Figma.", now.AddHours(-8));
        AddMsg(3, "Eve", "Love the new color scheme!", now.AddHours(-7),
            null, [new("❤️", ["Diana"])]);
        var t3 = AddMsg(3, "Alice", "Should we use rounded or square corners for cards?", now.AddHours(-4));
        AddMsg(3, "Diana", "I prefer rounded — feels more modern.", now.AddHours(-3.5), t3.Id);
        AddMsg(3, "Eve", "Rounded +1, matches our brand guidelines.", now.AddHours(-3), t3.Id);

        // #random
        AddMsg(4, "Charlie", "Anyone up for lunch?", now.AddHours(-2));
        AddMsg(4, "Bob", "Sure! Sushi place?", now.AddHours(-1.9),
            null, [new("👍", ["Charlie", "Eve"])]);
        AddMsg(4, "Eve", "Count me in!", now.AddMinutes(-100));
    }

    private Message AddMsg(int channelId, string author, string content, DateTime sentAt,
        int? replyToId = null, List<Reaction>? reactions = null)
    {
        var msg = new Message(_nextMessageId++, channelId, author, content, sentAt, replyToId, reactions ?? []);
        _messages.Add(msg);
        return msg;
    }

    public Task<List<Channel>> GetChannelsAsync()
        => Task.FromResult(_channels.ToList());

    public Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take)
    {
        var result = _messages
            .Where(m => m.ChannelId == channelId && m.ReplyToId == null)
            .OrderByDescending(m => m.SentAt)
            .Skip(skip)
            .Take(take)
            .OrderBy(m => m.SentAt)
            .ToList();

        return Task.FromResult(result);
    }

    public Task<Message> SendMessageAsync(int channelId, string content, int? replyToId)
    {
        var msg = new Message(_nextMessageId++, channelId, "You", content, DateTime.UtcNow, replyToId, []);
        _messages.Add(msg);
        return Task.FromResult(msg);
    }

    public Task<List<Message>> GetThreadAsync(int rootMessageId)
    {
        var replies = _messages
            .Where(m => m.ReplyToId == rootMessageId)
            .OrderBy(m => m.SentAt)
            .ToList();

        return Task.FromResult(replies);
    }

    public Task AddReactionAsync(int messageId, string emoji)
    {
        var msg = _messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var reaction = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (reaction is not null)
            {
                if (!reaction.Users.Contains("You"))
                    reaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, ["You"]));
            }
        }
        return Task.CompletedTask;
    }

    public Task MarkChannelReadAsync(int channelId)
    {
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        return Task.CompletedTask;
    }
}

export function setupEnterKey(textarea, dotNetRef) {
    textarea.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            const value = textarea.value.trim();
            if (value) {
                dotNetRef.invokeMethodAsync('OnEnterPressed', value);
                textarea.value = '';
            }
        }
    });
}

export function getTextareaValue(textarea) {
    return textarea.value;
}

export function clearTextarea(textarea) {
    textarea.value = '';
}

const scrollState = new WeakMap();

export function observeScrollTop(element, dotNetRef) {
    scrollState.set(element, { debouncing: false });

    element.addEventListener('scroll', () => {
        const state = scrollState.get(element);
        if (element.scrollTop < 10 && state && !state.debouncing) {
            state.debouncing = true;
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
            setTimeout(() => { state.debouncing = false; }, 1000);
        }
    });
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function getScrollHeight(element) {
    return element ? element.scrollHeight : 0;
}

export function preserveScrollPosition(element, previousScrollHeight) {
    if (element) {
        element.scrollTop = element.scrollHeight - previousScrollHeight;
    }
}

