toolArgs.file_text:
export function setupEnterKey(textarea, dotNetRef) {
    textarea.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            const value = textarea.value.trim();
            if (value) {
                dotNetRef.invokeMethodAsync('OnEnterPressed', value);
                textarea.value = '';
            }
        }
    });
}

export function getTextareaValue(textarea) {
    return textarea.value;
}

export function clearTextarea(textarea) {
    textarea.value = '';
}

const scrollState = new WeakMap();

export function observeScrollTop(element, dotNetRef) {
    scrollState.set(element, { debouncing: false });

    element.addEventListener('scroll', () => {
        const state = scrollState.get(element);
        if (element.scrollTop < 10 && state && !state.debouncing) {
            state.debouncing = true;
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
            setTimeout(() => { state.debouncing = false; }, 1000);
        }
    });
}

export function scrollToBottom(element) {
    if (element) {
        element.scrollTop = element.scrollHeight;
    }
}

export function getScrollHeight(element) {
    return element ? element.scrollHeight : 0;
}

export function preserveScrollPosition(element, previousScrollHeight) {
    if (element) {
        element.scrollTop = element.scrollHeight - previousScrollHeight;
    }
}

