arguments.file_text:
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-input">
    <textarea @ref="textareaRef" placeholder="@Placeholder" rows="2"></textarea>
    <button @onclick="SendFromButton">@ButtonText</button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private ElementReference textareaRef;
    private IJSObjectReference? module;
    private DotNetObjectReference<MessageInput>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./chat.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("setupEnterKey", textareaRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnEnterPressed(string value)
    {
        if (!string.IsNullOrWhiteSpace(value))
            await OnSend.InvokeAsync(value.Trim());
    }

    private async Task SendFromButton()
    {
        if (module is null) return;
        var value = await module.InvokeAsync<string>("getTextareaValue", textareaRef);
        if (!string.IsNullOrWhiteSpace(value))
        {
            await OnSend.InvokeAsync(value.Trim());
            await module.InvokeVoidAsync("clearTextarea", textareaRef);
        }
    }

    public async ValueTask DisposeAsync()
    {
        dotNetRef?.Dispose();
        if (module is not null)
        {
            try { await module.DisposeAsync(); } catch (JSDisconnectedException) { }
        }
    }
}

.message-input {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 12px;
    font-size: 14px;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #1264a3;
}

.message-input button {
    align-self: flex-end;
    padding: 8px 20px;
    background: #1264a3;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.message-input button:hover {
    background: #0b4f8a;
}

.message-input button:disabled {
    background: #ccc;
    cursor: default;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background 0.12s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background: #1164a3;
}

.channel-header-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 15px;
    color: #ccc;
}

.channel-item.active .channel-name {
    color: #fff;
}

.channel-description {
    font-size: 12px;
    color: #9e9e9e;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-item.active .channel-description {
    color: rgba(255, 255, 255, 0.7);
}

.unread-badge {
    background: #e01e5a;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    padding: 1px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-sidebar {
    width: 260px;
    min-width: 260px;
    background: #1a1d21;
    color: #fff;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #333;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #333;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 15px;
    color: #1d1c1d;
}

.timestamp {
    font-size: 12px;
    color: #9e9e9e;
}

.message-content {
    font-size: 15px;
    line-height: 1.46;
    color: #1d1c1d;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    background: #f0f4ff;
    border: 1px solid #d0d8e8;
    border-radius: 12px;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.12s;
}

.reaction-badge:hover {
    background: #dde4f0;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 13px;
    color: #1264a3;
    font-weight: 600;
    cursor: pointer;
    background: none;
    border: none;
    padding: 2px 0;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.message-actions button {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 16px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-actions button:hover {
    background: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 90px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

.emoji-picker button {
    background: none;
    border: none;
    padding: 4px 6px;
    font-size: 20px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-picker button:hover {
    background: #f0f0f0;
}

@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-list" @ref="listElement">
    @if (IsLoadingMore)
    {
        <div class="loading-indicator">Loading older messages…</div>
    }
    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference listElement;
    private IJSObjectReference? module;
    private DotNetObjectReference<MessageList>? dotNetRef;
    private bool initialized;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>("import", "./chat.js");
            dotNetRef = DotNetObjectReference.Create(this);
            await module.InvokeVoidAsync("observeScrollTop", listElement, dotNetRef);
            await module.InvokeVoidAsync("scrollToBottom", listElement);
            initialized = true;
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public async Task ScrollToBottomAsync()
    {
        if (module is not null)
            await module.InvokeVoidAsync("scrollToBottom", listElement);
    }

    public async Task<double> GetScrollHeightAsync()
    {
