toolArgs.file_text:
.message-item {
    position: relative;
    padding: 8px 16px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 15px;
    color: #1d1c1d;
}

.timestamp {
    font-size: 12px;
    color: #9e9e9e;
}

.message-content {
    font-size: 15px;
    line-height: 1.46;
    color: #1d1c1d;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    background: #f0f4ff;
    border: 1px solid #d0d8e8;
    border-radius: 12px;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.12s;
}

.reaction-badge:hover {
    background: #dde4f0;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 13px;
    color: #1264a3;
    font-weight: 600;
    cursor: pointer;
    background: none;
    border: none;
    padding: 2px 0;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    z-index: 10;
}

.message-actions button {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 16px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-actions button:hover {
    background: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 90px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px;
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.15);
    z-index: 20;
}

.emoji-picker button {
    background: none;
    border: none;
    padding: 4px 6px;
    font-size: 20px;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-picker button:hover {
    background: #f0f0f0;
}

