    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

