    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background 0.1s;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root {
    padding: 12px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e0e0e0;
}

.thread-root .author {
    font-weight: 700;
    font-size: 14px;
    color: #1d1c1d;
}

.root-content {
    margin: 4px 0 0;
    font-size: 14px;
    color: #333;
}

