    padding: 8px 16px;
    text-align: center;
    font-size: 12px;
    color: #888;
    border-bottom: 1px solid #eee;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
