arguments.file_text:
@inherits LayoutComponentBase

<div class="chat-layout">
    @Body
</div>

.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    margin: 0;
    padding: 0;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_df10c1747d5642cf8cfc2b630c665fb0.Components.Chat
@inject IChatService ChatService

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-and-thread">
        <MessageArea @ref="messageAreaRef"
                     ChannelName="@(selectedChannel?.Name ?? "")"
                     ChannelDescription="@(selectedChannel?.Description ?? "")"
                     Messages="messages"
                     ThreadReplyCounts="threadReplyCounts"
                     IsLoadingMore="isLoadingMore"
                     OnLoadMore="LoadMoreMessages"
                     OnOpenThread="OpenThread"
                     OnReact="AddReaction"
                     OnSend="SendMessage" />

        @if (activeThreadRootId.HasValue)
        {
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnReplySend="SendThreadReply" />
        }
    </div>
</div>

@code {
    private List<Channel> channels = new();
    private int? selectedChannelId;
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private Dictionary<int, int> threadReplyCounts = new();
    private bool isLoadingMore;
    private int messagesSkip;
    private bool hasMoreMessages = true;
    private const int PageSize = 20;

    private int? activeThreadRootId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();

    private MessageArea? messageAreaRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
            await SelectChannel(channels[0].Id);
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages.Clear();
        threadReplyCounts.Clear();
        messagesSkip = 0;
        hasMoreMessages = true;
        activeThreadRootId = null;

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channelId);

        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
            channels[idx] = channels[idx] with { UnreadCount = 0 };
    }

    private async Task LoadMessages()
    {
        var loaded = await ChatService.GetMessagesAsync(selectedChannelId!.Value, messagesSkip, PageSize);
        if (loaded.Count < PageSize)
            hasMoreMessages = false;

        messages.InsertRange(0, loaded);
        messagesSkip += loaded.Count;

        await ComputeThreadCounts(loaded);
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        double prevHeight = 0;
        if (messageAreaRef is not null)
            prevHeight = await messageAreaRef.GetScrollHeightAsync();

        await LoadMessages();

        isLoadingMore = false;
        StateHasChanged();

        // Keep the user's scroll position after prepending older messages
        await Task.Yield();
        if (messageAreaRef is not null && prevHeight > 0)
            await messageAreaRef.PreserveScrollAsync(prevHeight);
    }

    private async Task ComputeThreadCounts(List<Message> msgs)
    {
        foreach (var msg in msgs.Where(m => m.ReplyToId == null))
        {
            var replies = await ChatService.GetThreadAsync(msg.Id);
            if (replies.Count > 0)
                threadReplyCounts[msg.Id] = replies.Count;
        }
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(msg);
        StateHasChanged();

        await Task.Yield();
        if (messageAreaRef is not null)
            await messageAreaRef.ScrollToBottomAsync();
    }

    private async Task OpenThread(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        StateHasChanged();
    }

    private void CloseThread()
    {
        activeThreadRootId = null;
        threadRootMessage = null;
        threadReplies.Clear();
    }

    private async Task SendThreadReply(string content)
    {
        if (activeThreadRootId is null || selectedChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId.Value, content, activeThreadRootId.Value);
        threadReplies.Add(reply);
        threadReplyCounts[activeThreadRootId.Value] = threadReplies.Count;
        StateHasChanged();
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var reaction = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (reaction is not null)
            {
                if (!reaction.Users.Contains("You"))
                    reaction.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            StateHasChanged();
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.main-and-thread {
    flex: 1;
    display: flex;
    min-width: 0;
    overflow: hidden;
}

